async function bindleftCommonSearchdropdown(instance,fieldName) {
    var vm = instance;
    var params='';
    if(fieldName == 'STATE'){
         params = `countryId=223&includeCandaState=true`;
        await DataService.GetStateListByCountryId(params).then((response) => {
            if (response.data && response.data.result) {                
                const targetField = vm.leftSearchFields.find(field => field.fieldName === 'STATE'); // Find the field by name
                if (targetField) {
                    targetField.listOptions = response.data.result.map(element => ({ name:  element.STATE_NAME + '(' + element.ISO_CODE_3 + ')', value: element.ISO_CODE_3 }));
                }
            } 
        });
    }
    else if(fieldName == 'UTILITIES'){
        await DataService.GetDdlUtility().then((response) => {
            if (response.data) {   
                const mappedData = response.data.map(element => ({ 
                    name: element.UTILITY_NAME, 
                    value: element.UTILITY_NAME 
                }));
        
                const targetField = vm.leftSearchFields.find(field => field.fieldName === 'UtilityName');
                
                if (targetField) {
                    targetField.listOptions = mappedData;
                }
            } 
        });
    }
}
export default { buttons, leftsearchSchema, listActions, bindleftCommonSearchdropdown };